-- ============================================================
-- Smart Library System — MySQL Setup Script (FINAL)
-- ONE unified table: books
-- Columns: book_number, rfid_uid, title, author,
--          programme, subject, rack, expected_shelf
-- Run in MySQL Workbench: File > Open SQL Script
--   Then press: Ctrl + Shift + Enter  (Run All)
-- ============================================================

CREATE DATABASE IF NOT EXISTS library_db;
USE library_db;

-- Drop old tables for a clean start
DROP TABLE IF EXISTS rfid_books;
DROP TABLE IF EXISTS books;

-- ── Unified books table ──────────────────────────────────────
-- book_number  → Camera Scan uses this (OCR reads label sticker)
-- rfid_uid     → RFID Scan uses this (ESP32 scans NFC tag, NULL for most books)
-- programme    → Programme / Discipline (e.g. "Computer Engineering (B.Tech)")
-- subject      → Detailed subject (e.g. "Mathematics")
-- rack         → Physical rack e.g. Rack-1
-- expected_shelf → Shelf ID e.g. A1
CREATE TABLE books (
    id             BIGINT       AUTO_INCREMENT PRIMARY KEY,
    book_number    VARCHAR(20)  UNIQUE,
    rfid_uid       VARCHAR(20)  UNIQUE,
    title          VARCHAR(600) NOT NULL,
    author         VARCHAR(300),
    programme      VARCHAR(300),
    subject        VARCHAR(300),
    rack           VARCHAR(20),
    expected_shelf VARCHAR(10)
);

CREATE INDEX idx_rfid ON books(rfid_uid);
CREATE INDEX idx_bn   ON books(book_number);
















